navbar_sticky.css:
.navbar { position: sticky; top: 0; z-index: 1000; background: rgba(255,255,255,0.95); backdrop-filter: blur(10px); padding: 1rem 0; border-bottom: 1px solid var(--border); transition: all 0.3s ease; }
.navbar .container { max-width: 1200px; margin: 0 auto; padding: 0 1.5rem; display: flex; align-items: center; justify-content: space-between; }
.navbar .logo { display: flex; align-items: center; gap: 0.5rem; }
.navbar .logo h1 { font-size: 1.4rem; font-weight: 700; color: var(--primary); }
.nav-links { display: flex; gap: 2rem; list-style: none; }
.nav-links a { text-decoration: none; color: var(--text); font-weight: 500; transition: color 0.3s; }
.nav-links a:hover, .nav-links a.active { color: var(--primary); }
.nav-cta { background: var(--primary); color: #fff; border: none; padding: 0.6rem 1.5rem; border-radius: 50px; cursor: pointer; font-size: 0.9rem; font-weight: 600; transition: all 0.3s; }
.nav-cta:hover { transform: translateY(-2px); box-shadow: 0 4px 15px rgba(0,0,0,0.2); }
.hamburger { display: none; flex-direction: column; gap: 5px; cursor: pointer; }
.hamburger span { width: 25px; height: 2px; background: var(--text); transition: all 0.3s; }
@media (max-width: 768px) { .hamburger { display: flex; } .nav-links { display: none; position: absolute; top: 100%; right: 0; left: 0; background: #fff; padding: 1rem; flex-direction: column; gap: 1rem; } .nav-links.active { display: flex; } }

hero_fullscreen.css:
.hero { min-height: 100vh; background: linear-gradient(135deg, var(--primary) 0%, var(--secondary) 100%); display: flex; align-items: center; justify-content: center; text-align: center; position: relative; overflow: hidden; }
.hero-content { max-width: 800px; padding: 2rem; color: #fff; z-index: 1; }
.hero-content h2 { font-size: clamp(2rem, 5vw, 3.5rem); font-weight: 900; line-height: 1.2; margin-bottom: 1rem; }
.hero-content p { font-size: 1.1rem; opacity: 0.9; margin-bottom: 2rem; line-height: 1.8; }
.hero-btns { display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap; }
.btn-primary { background: #fff; color: var(--primary); padding: 0.9rem 2rem; border-radius: 50px; text-decoration: none; font-weight: 700; transition: all 0.3s; }
.btn-primary:hover { transform: translateY(-3px); box-shadow: 0 8px 25px rgba(0,0,0,0.2); }
.btn-secondary { border: 2px solid #fff; color: #fff; padding: 0.9rem 2rem; border-radius: 50px; text-decoration: none; font-weight: 600; transition: all 0.3s; }
.btn-secondary:hover { background: rgba(255,255,255,0.1); }

cards_grid.css:
.section-header { text-align: center; margin-bottom: 3rem; }
.section-header h2 { font-size: 2rem; font-weight: 700; color: var(--text); margin-bottom: 0.5rem; }
.section-header p { color: var(--text-light); font-size: 1rem; }
.cards-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem; }
.card { background: #fff; border-radius: 16px; padding: 2rem; text-align: center; transition: all 0.3s; border: 1px solid var(--border); }
.card:hover { transform: translateY(-8px); box-shadow: 0 20px 40px rgba(0,0,0,0.1); border-color: var(--primary); }
.card-icon { width: 64px; height: 64px; background: var(--bg-light); border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 1rem; }
.card-icon i { font-size: 1.5rem; color: var(--primary); }
.card h3 { font-size: 1.1rem; font-weight: 700; margin-bottom: 0.5rem; color: var(--text); }
.card p { color: var(--text-light); font-size: 0.9rem; line-height: 1.7; }

stats_counter.css:
.stats { background: var(--primary); padding: 4rem 0; color: #fff; }
.stats-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 2rem; text-align: center; }
.stat-number { font-size: 2.5rem; font-weight: 900; margin-bottom: 0.5rem; }
.stat-label { font-size: 0.9rem; opacity: 0.85; }

testimonials.css:
.testimonials { padding: 5rem 0; background: var(--bg); }
.testimonials-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; }
.testimonial-card { background: #fff; border-radius: 16px; padding: 2rem; border: 1px solid var(--border); transition: all 0.3s; }
.testimonial-card:hover { box-shadow: 0 10px 30px rgba(0,0,0,0.08); }
.stars { color: #f59e0b; font-size: 1.2rem; margin-bottom: 1rem; }
.testimonial-card p { color: var(--text-light); line-height: 1.8; margin-bottom: 1.5rem; font-style: italic; }
.client { display: flex; flex-direction: column; }
.client strong { color: var(--text); font-weight: 700; }
.client span { color: var(--text-light); font-size: 0.85rem; }

contact_form.css:
.contact { padding: 5rem 0; }
.contact-form { max-width: 600px; margin: 0 auto; }
.form-group { margin-bottom: 1.2rem; }
.form-group input, .form-group textarea { width: 100%; padding: 0.9rem 1.2rem; border: 1.5px solid var(--border); border-radius: 12px; font-family: inherit; font-size: 0.95rem; transition: border-color 0.3s; outline: none; background: #fff; color: var(--text); }
.form-group input:focus, .form-group textarea:focus { border-color: var(--primary); }
.btn-submit { width: 100%; background: var(--primary); color: #fff; border: none; padding: 1rem; border-radius: 12px; font-size: 1rem; font-weight: 700; cursor: pointer; transition: all 0.3s; }
.btn-submit:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(0,0,0,0.15); }

footer_full.css:
.footer { background: #0f172a; color: #cbd5e1; padding: 4rem 0 1.5rem; }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 2rem; margin-bottom: 3rem; }
.footer-brand h3 { color: #fff; font-size: 1.4rem; margin-bottom: 0.8rem; }
.footer-brand p { font-size: 0.9rem; line-height: 1.7; }
.footer-links h4, .footer-contact h4 { color: #fff; margin-bottom: 1rem; font-size: 1rem; }
.footer-links { display: flex; flex-direction: column; gap: 0.5rem; }
.footer-links a { color: #cbd5e1; text-decoration: none; font-size: 0.9rem; transition: color 0.3s; }
.footer-links a:hover { color: var(--primary); }
.footer-contact p { font-size: 0.9rem; margin-bottom: 0.5rem; display: flex; align-items: center; gap: 0.5rem; }
.footer-bottom { border-top: 1px solid #1e293b; padding-top: 1.5rem; text-align: center; font-size: 0.85rem; }
